try:
    entity_name = (entity_name or '').strip()
    assert entity_name, 'Missing required param: entity_name'

    lastIngestTime = (lastIngestTime or '').strip()
    if not lastIngestTime:
        print(
            'WARNING: lastIngestTime is empty — watermark upsert will be skipped. '
            'When called from pln_service_bus this should always be set to max_message_enqueued_time_utc.'
        )

except Exception as e:
    error_message = f"Error validating input parameters: {str(e)[:800]}"
    end_exec_time = datetime.now()

def _to_dict(x):
    """
    Parse runContextJson tolerating:
    - dict
    - JSON string
    - double escaped JSON string
    """
    global error_message, end_exec_time

    if not error_message:
        try:
            if isinstance(x, dict):
                return x

            if not x:
                return {}

            try:
                return json.loads(x)
            except Exception:
                return json.loads(bytes(x, "utf-8").decode("unicode_escape"))

        except Exception as e:
            error_message = f"Error parsing runContextJson: {str(e)[:800]}"
            end_exec_time = datetime.now()
            return {}

    return {}


def _utc_now_iso():
    global error_message, end_exec_time

    if not error_message:
        try:
            return datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")

        except Exception as e:
            error_message = f"Error generating UTC ISO timestamp: {str(e)[:800]}"
            end_exec_time = datetime.now()
            return None

    return None


def _utc_now_ts():
    global error_message, end_exec_time

    if not error_message:
        try:
            return datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")

        except Exception as e:
            error_message = f"Error generating UTC timestamp: {str(e)[:800]}"
            end_exec_time = datetime.now()
            return None

    return None

if not error_message:
    try:
        result = json.dumps({
            "manifestPath": manifest_path,
            "records": int(recordsIngested),
            "filesWritten": int(files_written),
            "status": status
        })
    except Exception as e:
        error_message = str(e)

if not error_message:
    mssparkutils.notebook.exit(result)
